const safe = (fn, fb) => { try { return fn(); } catch { return fb; } };
const form = () => $('form_data').first();

const handbookText =
  safe(() => $('pdf_extractor').first().json.text, '') || '(no handbook provided)';

let codeText =
  safe(() => { const j = $('code_extractor').first().json; return j.text ?? j.data; }, '')
  || '(no source code provided)';
codeText = codeText.slice(0, 8000);

const goal  = safe(() => form().json['Study goal'], '');
const level = safe(() => form().json['Your level'], 'Unspecified');
const email = safe(() => form().json['Email'], '');
const timezone = safe(() => form().json['Timezone'], 'UTC');

const prefLabels = [
  'When you take in new information, you learn best by',
  'You remember new material best when you',
  'When researching a topic on your own, you prefer to',
  'Your ideal study session looks like',
  'When memorising facts or terms, you',
  "When following a new procedure, you'd rather",
  'To understand how something works, you'
];
const tally = { Visual: 0, Auditory: 0, 'Reading/Writing': 0, Kinesthetic: 0 };
const answers = [];
for (const label of prefLabels) {
  const a = safe(() => form().json[label], '');
  if (!a) continue;
  answers.push(`- ${label}: ${a}`);
  const key = a.split('—')[0].trim();
  if (key in tally) tally[key]++;
}
const max = Math.max(0, ...Object.values(tally));
const dominant = max === 0
  ? 'Unspecified'
  : Object.keys(tally).filter(k => tally[k] === max).join(' / ');

const prefsBlock = answers.length
  ? `Dominant style: ${dominant}
${answers.join('
')}`
  : '(no learning preferences provided)';

const commitmentsBlock = safe(() => $('parse_commitments').first().json.commitmentsBlock, '');

const prompt =
`STUDY GOAL:
${goal}

SELF-ASSESSED LEVEL: ${level}

=== LEARNING PREFERENCES ===
${prefsBlock}

=== MODULE HANDBOOK ===
${handbookText}

=== SOURCE CODE ===
${codeText}${commitmentsBlock}`;

return [{ json: { prompt, dominant, email, timezone } }];

const fs = require('fs');
const dir = '/data/flagged';
fs.mkdirSync(dir, { recursive: true });
const report = $json.report || '';
const name = (($json.name) || 'student').replace(/[^a-z0-9]+/gi, '_').toLowerCase();
const stamp = new Date().toISOString().slice(0,19).replace(/[:T]/g,'-');
const path = `${dir}/plan-${name}-${stamp}.md`;
fs.writeFileSync(path, report);
return [{ json: { saved: path, bytes: report.length, report, name } }];

const safe = (fn, fb) => { try { return fn(); } catch { return fb; } };

const f = $('form_data').first().json;

const rating  = safe(() => Number($('Feedback').first().json['Rating']), 0) || 0;
const comment = safe(() => String($('Feedback').first().json['Comments'] || '').trim(), '');

const student = safe(() => f['Student Name'], 'Student');
const email   = safe(() => f['Email'], '');
const level   = safe(() => f['Your level'], 'Unspecified');
const goal    = safe(() => f['Study goal'], '');

// the full assembled inputs the plan was built from (handbook + level + prefs + code)
const inputs  = safe(() => String($('context').first().json.prompt || ''), '').slice(0, 12000);
// the actual generated plan markdown
const plan    = safe(() => String($('save_report').first().json.report || ''), '');

const stamp = new Date().toISOString();
const feedback_id = `${stamp}__${String(student).replace(/[^a-z0-9]+/gi, '_').toLowerCase()}`;

return [{ json: {
  feedback_id,
  created_at: stamp,
  student,
  email,
  level,
  goal,
  inputs,
  plan,
  rating,
  comment,
  evaluated: false
} }];

const fs = require('fs');
const safe = (fn, fb) => { try { return fn(); } catch { return fb; } };

const dir = '/data/flagged';
try { fs.mkdirSync(dir, { recursive: true }); } catch {}

const DOW = { sunday:0, monday:1, tuesday:2, wednesday:3, thursday:4, friday:5, saturday:6 };
const pad = n => String(n).padStart(2, '0');

function defaultEnd(start) {
  const [h, m] = String(start || '09:00').split(':').map(x => parseInt(x, 10) || 0);
  return `${pad((h + 1) % 24)}:${pad(m)}`;
}

function dateForDow(dow) {
  const now = new Date();
  const dayOfWeek = now.getDay();
  const mondayOffset = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
  const monday = new Date(now.getFullYear(), now.getMonth(), now.getDate() + mondayOffset);
  const targetOffset = dow === 0 ? 6 : dow - 1;
  return new Date(monday.getFullYear(), monday.getMonth(), monday.getDate() + targetOffset);
}

function fmt(d, hhmm) {
  const [h, m] = String(hhmm || '09:00').split(':').map(x => parseInt(x, 10) || 0);
  return `${d.getFullYear()}${pad(d.getMonth()+1)}${pad(d.getDate())}T${pad(h)}${pad(m)}00`;
}

function esc(t) {
  return String(t || 'Study session')
    .replace(/\/g, '\\').replace(/;/g, '\;').replace(/,/g, '\,').replace(/?
/g, '\n');
}

const raw = $json.output ?? $json.text ?? '';
let events = [];
let weeks = 12;
const cleaned = String(raw).replace(/<\|?[a-z_]+\|?>/gi, '')
  .replace(/```[a-z]*
?/gi, '').replace(/```/g, '');

try {
  const p = JSON.parse(cleaned);
  if (p && Array.isArray(p.events)) { events = p.events; weeks = Number(p.weeks) || 12; }
  else if (Array.isArray(p)) { events = p; }
} catch {
  const i = cleaned.indexOf('['), j = cleaned.lastIndexOf(']');
  if (i !== -1 && j > i) {
    try { const a = JSON.parse(cleaned.slice(i, j + 1)); if (Array.isArray(a)) events = a; } catch {}
  }
}

events = events.filter(e => e && e.day && e.start);

const src = $('save_report').first().json;
const name = src.name || 'student';
const timezone = safe(() => $('context').first().json.timezone, 'UTC');

const now = new Date();
const dtstamp = `${now.getUTCFullYear()}${pad(now.getUTCMonth()+1)}${pad(now.getUTCDate())}T${pad(now.getUTCHours())}${pad(now.getUTCMinutes())}${pad(now.getUTCSeconds())}Z`;

const lines = ['BEGIN:VCALENDAR', 'VERSION:2.0', 'PRODID:-//Study Planner//EN',
  'CALSCALE:GREGORIAN', 'METHOD:PUBLISH'];

events.forEach((e, idx) => {
  const key = String(e.day).trim().toLowerCase();
  if (!(key in DOW)) return;
  if (!/^\d{1,2}:\d{2}$/.test(e.start)) return;
  const endTime = e.end || defaultEnd(e.start);
  if (!/^\d{1,2}:\d{2}$/.test(endTime)) return;

  const d = dateForDow(DOW[key]);
  lines.push('BEGIN:VEVENT',
    `UID:study-${idx}-${Date.now()}@study-planner`,
    `DTSTAMP:${dtstamp}`,
    `DTSTART;TZID=${timezone}:${fmt(d, e.start)}`,
    `DTEND;TZID=${timezone}:${fmt(d, endTime)}`,
    `RRULE:FREQ=WEEKLY;COUNT=${weeks}`,
    `SUMMARY:${esc(e.title)}`,
    'END:VEVENT');
});
lines.push('END:VCALENDAR');
const ics = lines.join('
') + '
';

const safeName = String(name).replace(/[^a-z0-9]+/gi, '_').toLowerCase();
const stamp = new Date().toISOString().slice(0, 19).replace(/[:T]/g, '-');
const path = `${dir}/plan-${safeName}-${stamp}.ics`;

try { fs.writeFileSync(path, ics); }
catch (err) {
  return [{ json: { ics_saved: null, events: 0, error: err.message,
    report: src.report, name, saved: src.saved } }];
}

return [{ json: { ics_saved: path, events: events.length, weeks,
  report: src.report, name, saved: src.saved } }];

const fs = require('fs');

// Pull the generated content from build_ics BY NAME, so it doesn't matter that
// the feedback/logging steps dropped the binary along the way.
const info    = $('build_ics').first().json;
const planMd  = info.report || '';     // the full markdown study plan
const icsPath = info.ics_saved;        // path to the .ics already written to disk

const planBuf = Buffer.from(planMd, 'utf8');
const icsBuf  = fs.readFileSync(icsPath);   // read the .ics back from disk

return [{
  json: { bundled: true },
  binary: {
    plan: {
      data: planBuf.toString('base64'),
      fileName: 'study-plan.md',
      mimeType: 'text/markdown',
    },
    calendar: {
      data: icsBuf.toString('base64'),
      fileName: 'study-plan.ics',
      mimeType: 'text/calendar',
    },
  },
}];

const safe = (fn, fb) => { try { return fn(); } catch { return fb; } };
const name = safe(() => $('form_data').first().json['Student Name'], 'Student');
const plan     = safe(() => $('plan_agent').first().json.output, '');
const wellness = safe(() => $('wellness_agent').first().json.output, '');
const sustain  = safe(() => $('sustainability_agent').first().json.output, '');

const report =
`# Study Plan — ${name}

${plan}

---

## Wellness check
${wellness}

---

## Sustainability
${sustain}
`;
return [{ json: { report, name } }];

const safe = (fn, fb) => { try { return fn(); } catch { return fb; } };

const p1 = safe(() => $('Page 1 - Your details').first().json, {});
const p2 = safe(() => $('Page 2 - Study goal').first().json, {});
const p4 = safe(() => $('Page 4 - Your level').first().json, {});
const p5a = safe(() => $('Page 5 - Learning style - 1').first().json, {});
const p5b = safe(() => $('Page 5 - Learning style - 2').first().json, {});
const p5c = safe(() => $('Page 5 - Learning style - 3').first().json, {});
const p5d = safe(() => $('Page 5 - Learning style - 4').first().json, {});
const p5 = { ...p5a, ...p5b, ...p5c, ...p5d };
const p6 = safe(() => $('Page 6 - Calendar delivery').first().json, {});

const json = { ...p1, ...p2, ...p4, ...p5, ...p6 };
const binary = safe(() => $('Page 3 - Uploads').first().binary, {}) || {};

return [{ json, binary }];

const fs = require('fs');
const src  = $('build_ics').first().json.ics_saved;     // this run's .ics
const dest = '/data/flagged/study-calendar.ics';        // the file Calendar subscribes to
fs.copyFileSync(src, dest);
return [{ json: { published: true, calendar_file: dest } }];

const safe = (fn, fb) => { try { return fn(); } catch { return fb; } };
const raw = safe(() => $('form_data').first().json['Existing weekly commitments'], '');
const lines = String(raw).split('
').map(l => l.trim()).filter(Boolean);

const DOW = { monday:1, tuesday:2, wednesday:3, thursday:4, friday:5, saturday:6, sunday:0 };
const re1 = /^(\w+)\s+(\d{1,2}:\d{2})\s*[-–]\s*(\d{1,2}:\d{2})\s+(.+)$/;
const re2 = /^(\w+)\s+(\d{1,2}:\d{2})\s+(.+)$/;

const commitments = [];
for (const line of lines) {
  let m = line.match(re1);
  if (m) {
    const [, day, start, end, title] = m;
    if (day.toLowerCase() in DOW) commitments.push({ day, start, end, title });
    continue;
  }
  m = line.match(re2);
  if (m) {
    const [, day, start, title] = m;
    if (day.toLowerCase() in DOW) {
      const [h, mi] = start.split(':').map(Number);
      const end = `${String((h + 1) % 24).padStart(2, '0')}:${String(mi).padStart(2, '0')}`;
      commitments.push({ day, start, end, title });
    }
  }
}

const block = commitments.length
  ? '

EXISTING WEEKLY COMMITMENTS (work around these — never schedule study sessions during these times):
'
    + commitments.map(c => `- ${c.day} ${c.start}-${c.end}: ${c.title}`).join('
')
  : '';

return [{ json: { commitmentsBlock: block, commitments } }];
